type AuthoredLessonModuleSeed = {
  title: string;
  moduleType?: LessonModuleType;
  teachingScript: Record<string, unknown>;
  exampleCount?: number;
  estimatedMinutes?: number;
  tutorVisible?: boolean;
  sequenceOrder?: number;
  contentStatus?: ContentStatus;
};

export type AuthoredNodeSeed = {
  lessonModule: AuthoredLessonModuleSeed;
  questions: Partial<Record<QuestionPoolType, AuthoredQuestionSeed>>;
};

const authoredStatus = ContentStatus.QA_REVIEW;

function authoredQuestion(seed: AuthoredQuestionSeed): AuthoredQuestionSeed {
  return {
    autoMarkable: true,
    contentStatus: authoredStatus,
    ...seed,
  };
}

function authoredModule(seed: AuthoredLessonModuleSeed): AuthoredLessonModuleSeed {
  return {
    moduleType: LessonModuleType.MICRO_LESSON,
    exampleCount: 3,
    estimatedMinutes: 8,
    tutorVisible: true,
    sequenceOrder: 1,
    contentStatus: authoredStatus,
    ...seed,
  };
}

